import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { 
  FaUser, 
  FaUserMd, 
  FaPills, 
  FaEye, 
  FaEyeSlash, 
  FaSpinner, 
  FaHeartbeat,
  FaChevronDown,
  FaInfoCircle,
  FaGlobe
} from 'react-icons/fa';

const Login = ({ onLogin }) => {
  const { t, i18n } = useTranslation();
  const [selectedRole, setSelectedRole] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [step, setStep] = useState('role'); // role, credentials
  const [isLoading, setIsLoading] = useState(false);
  const [showPassword, setShowPassword] = useState(false);
  const [language, setLanguage] = useState('en');
  const [error, setError] = useState('');
  const [showCredentials, setShowCredentials] = useState(false);

  const roles = [
    {
      id: 'patient',
      name: t('patient') || 'Patient',
      icon: FaUser,
      gradient: 'from-blue-500 to-blue-600',
      bgColor: 'bg-blue-50',
      borderColor: 'border-blue-200',
      hoverBg: 'hover:bg-blue-100',
      textColor: 'text-blue-700',
      description: 'Access medical consultations and health records',
      usernamePrefix: 'p',
      sampleUsername: 'p001'
    },
    {
      id: 'doctor',
      name: t('doctor') || 'Doctor',
      icon: FaUserMd,
      gradient: 'from-green-500 to-green-600',
      bgColor: 'bg-green-50',
      borderColor: 'border-green-200',
      hoverBg: 'hover:bg-green-100',
      textColor: 'text-green-700',
      description: 'Manage appointments and patient consultations',
      usernamePrefix: 'd',
      sampleUsername: 'd001'
    },
    {
      id: 'pharmacist',
      name: t('pharmacist') || 'Pharmacist',
      icon: FaPills,
      gradient: 'from-purple-500 to-purple-600',
      bgColor: 'bg-purple-50',
      borderColor: 'border-purple-200',
      hoverBg: 'hover:bg-purple-100',
      textColor: 'text-purple-700',
      description: 'Manage prescriptions and medicine inventory',
      usernamePrefix: 'pm',
      sampleUsername: 'pm001'
    }
  ];

  const languages = [
    { code: 'en', name: 'English', flag: '🇺🇸' },
    { code: 'hi', name: 'हिंदी', flag: '🇮🇳' },
    { code: 'pa', name: 'ਪੰਜਾਬੀ', flag: '🇮🇳' }
  ];

  const handleRoleSelect = (role) => {
    setSelectedRole(role);
    setStep('credentials');
    setError('');
    setUsername('');
    setPassword('');
  };

  const handleLogin = async () => {
    if (!username || !password) {
      setError('Please enter both username and password');
      return;
    }
    
    setIsLoading(true);
    setError('');
    
    try {
      const response = await fetch('http://localhost:5000/api/auth/login', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          username: username,
          password: password
        })
      });
      
      const data = await response.json();
      
      if (response.ok) {
        // Store token in localStorage
        localStorage.setItem('token', data.token);
        localStorage.setItem('user', JSON.stringify(data.user));
        
        // Call onLogin with user data
        onLogin({
          ...data.user,
          token: data.token
        });
      } else {
        setError(data.message || 'Login failed');
      }
    } catch (err) {
      console.error('Login error:', err);
      setError('Network error. Please check your connection.');
    } finally {
      setIsLoading(false);
    }
  };

  const changeLanguage = (langCode) => {
    setLanguage(langCode);
    i18n.changeLanguage(langCode);
  };

  const getCurrentRole = () => {
    return roles.find(role => role.id === selectedRole);
  };

  const handleBack = () => {
    setStep('role');
    setSelectedRole('');
    setError('');
    setUsername('');
    setPassword('');
  };

  const getPasswordForRole = (role) => {
    switch(role) {
      case 'patient': return 'patient123';
      case 'doctor': return 'doctor123';
      case 'pharmacist': return 'pharmacy123';
      default: return '';
    }
  };

  const fillSampleCredentials = () => {
    const role = getCurrentRole();
    if (role) {
      setUsername(role.sampleUsername);
      setPassword(getPasswordForRole(selectedRole));
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-green-50 relative overflow-hidden">
      {/* Enhanced Background Pattern */}
      <div className="absolute inset-0 opacity-10">
        <div className="absolute top-20 left-20 w-96 h-96 bg-gradient-to-r from-blue-400 to-indigo-500 rounded-full mix-blend-multiply filter blur-xl animate-pulse"></div>
        <div className="absolute top-40 right-20 w-80 h-80 bg-gradient-to-r from-green-400 to-emerald-500 rounded-full mix-blend-multiply filter blur-xl animate-pulse delay-1000"></div>
        <div className="absolute bottom-20 left-1/2 w-72 h-72 bg-gradient-to-r from-purple-400 to-violet-500 rounded-full mix-blend-multiply filter blur-xl animate-pulse delay-2000"></div>
        <div className="absolute top-1/2 left-10 w-48 h-48 bg-gradient-to-r from-pink-300 to-rose-400 rounded-full mix-blend-multiply filter blur-xl animate-pulse delay-3000"></div>
      </div>
      
      {/* Floating Medical Icons */}
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 left-1/4 opacity-5 animate-float">
          <FaHeartbeat className="text-6xl text-red-400" />
        </div>
        <div className="absolute top-3/4 right-1/4 opacity-5 animate-float-delayed">
          <FaPills className="text-5xl text-purple-400" />
        </div>
        <div className="absolute top-1/2 right-1/3 opacity-5 animate-float-slow">
          <FaUserMd className="text-4xl text-green-400" />
        </div>
      </div>

      <div className="relative z-10 min-h-screen flex items-center justify-center p-4">
        <div className="w-full max-w-lg">
          {/* Language Selector */}
          <div className="mb-8 flex justify-center">
            <div className="bg-white/80 backdrop-blur-sm rounded-2xl p-2 shadow-lg border border-white/20">
              <div className="flex items-center gap-2">
                <FaGlobe className="text-gray-500 ml-2" />
                {languages.map((lang) => (
                  <button
                    key={lang.code}
                    onClick={() => changeLanguage(lang.code)}
                    className={`px-4 py-2 rounded-xl text-sm font-medium transition-all duration-200 flex items-center gap-2 ${
                      language === lang.code
                        ? 'bg-gradient-to-r from-blue-500 to-blue-600 text-white shadow-lg transform scale-105'
                        : 'text-gray-600 hover:bg-blue-50 hover:scale-105'
                    }`}
                  >
                    <span>{lang.flag}</span>
                    <span>{lang.name}</span>
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Enhanced Logo and Title */}
          <div className="text-center mb-12">
            <div className="relative mx-auto mb-8 w-32 h-32">
              {/* Multiple Shadow Layers for Depth */}
              <div className="absolute inset-2 bg-gradient-to-r from-blue-600 to-green-500 rounded-3xl shadow-2xl transform rotate-6 opacity-20"></div>
              <div className="absolute inset-1 bg-gradient-to-r from-blue-500 to-green-500 rounded-3xl shadow-xl transform rotate-3 opacity-40"></div>
              <div className="relative bg-gradient-to-r from-blue-600 to-green-600 rounded-3xl flex items-center justify-center w-full h-full shadow-2xl border-4 border-white transform hover:scale-110 transition-transform duration-300">
                <FaHeartbeat className="text-white text-4xl animate-pulse" />
              </div>
              {/* Glowing Ring Effect */}
              <div className="absolute inset-0 rounded-3xl bg-gradient-to-r from-blue-400 to-green-400 opacity-30 blur-md animate-pulse"></div>
            </div>
            <h1 className="text-5xl font-bold bg-gradient-to-r from-blue-700 via-blue-600 to-green-600 bg-clip-text text-transparent mb-4 tracking-tight">
              Helio
            </h1>
            <div className="space-y-2">
              <p className="text-gray-700 text-xl font-semibold">Bringing Healthcare Closer to You</p>
              <div className="flex items-center justify-center gap-2 text-gray-600">
                <span className="w-2 h-2 bg-red-400 rounded-full animate-pulse"></span>
                <p className="text-base font-medium">Rural Healthcare • Punjab, India</p>
                <span className="w-2 h-2 bg-green-400 rounded-full animate-pulse delay-500"></span>
              </div>
            </div>
          </div>

          <div className="bg-white/90 backdrop-blur-lg rounded-3xl shadow-2xl border border-white/20 overflow-hidden">
            {/* Step 1: Role Selection */}
            {step === 'role' && (
              <div className="p-8">
                <div className="text-center mb-8">
                  <h2 className="text-2xl font-bold text-gray-800 mb-2">Choose Your Role</h2>
                  <p className="text-gray-600">Select how you'd like to access Helio</p>
                </div>
                
                <div className="space-y-4 mb-8">
                  {roles.map((role) => {
                    const IconComponent = role.icon;
                    return (
                      <button
                        key={role.id}
                        onClick={() => handleRoleSelect(role.id)}
                        className={`w-full p-6 border-2 ${role.borderColor} ${role.bgColor} rounded-2xl ${role.hoverBg} transition-all duration-300 transform hover:scale-105 hover:shadow-lg group`}
                      >
                        <div className="flex items-center gap-5">
                          <div className={`w-16 h-16 bg-gradient-to-r ${role.gradient} rounded-2xl flex items-center justify-center shadow-lg group-hover:shadow-xl transition-shadow`}>
                            <IconComponent className="text-white text-2xl" />
                          </div>
                          <div className="text-left flex-1">
                            <h3 className={`font-bold text-lg ${role.textColor} mb-1`}>{role.name}</h3>
                            <p className="text-gray-600 text-sm mb-2">{role.description}</p>
                            <div className="flex items-center gap-2">
                              <span className="text-xs bg-white/60 px-2 py-1 rounded-full text-gray-600">
                                Sample: {role.sampleUsername}
                              </span>
                            </div>
                          </div>
                        </div>
                      </button>
                    );
                  })}
                </div>
                
                {/* Demo Credentials Info */}
                <div className="border-t border-gray-100 pt-6">
                  <button
                    onClick={() => setShowCredentials(!showCredentials)}
                    className="w-full flex items-center justify-between p-4 bg-blue-50 rounded-xl hover:bg-blue-100 transition-colors"
                  >
                    <div className="flex items-center gap-3">
                      <FaInfoCircle className="text-blue-600" />
                      <span className="font-semibold text-blue-800">Demo Credentials</span>
                    </div>
                    <FaChevronDown className={`text-blue-600 transition-transform ${showCredentials ? 'rotate-180' : ''}`} />
                  </button>
                  
                  {showCredentials && (
                    <div className="mt-4 p-4 bg-gradient-to-r from-blue-50 to-green-50 rounded-xl border-l-4 border-blue-400">
                      <div className="space-y-3 text-sm">
                        <div className="flex justify-between items-center">
                          <span className="font-semibold text-blue-700">👤 Patients:</span>
                          <span className="text-gray-700">p001, p002, p003</span>
                        </div>
                        <div className="flex justify-between items-center">
                          <span className="font-semibold text-green-700">👨‍⚕️ Doctors:</span>
                          <span className="text-gray-700">d001, d002, d003</span>
                        </div>
                        <div className="flex justify-between items-center">
                          <span className="font-semibold text-purple-700">💊 Pharmacists:</span>
                          <span className="text-gray-700">pm001, pm002, pm003</span>
                        </div>
                        <div className="mt-3 pt-3 border-t border-gray-200">
                          <p className="text-xs text-gray-600">
                            <strong>Passwords:</strong> patient123, doctor123, pharmacy123
                          </p>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>
            )}

            {/* Step 2: Login Credentials */}
            {step === 'credentials' && (
              <div className="p-8">
                <div className="text-center mb-8">
                  <div className={`w-20 h-20 bg-gradient-to-r ${getCurrentRole()?.gradient} rounded-2xl mx-auto mb-4 flex items-center justify-center shadow-lg`}>
                    {React.createElement(getCurrentRole()?.icon, { className: "text-white text-3xl" })}
                  </div>
                  <h2 className="text-2xl font-bold text-gray-800 mb-1">{getCurrentRole()?.name} Login</h2>
                  <p className="text-gray-600">Enter your credentials to continue</p>
                </div>

                {error && (
                  <div className="mb-6 p-4 bg-red-50 border-l-4 border-red-400 rounded-xl">
                    <div className="flex items-center gap-3">
                      <div className="w-6 h-6 bg-red-100 rounded-full flex items-center justify-center">
                        <span className="text-red-600 text-sm">!</span>
                      </div>
                      <p className="text-red-700 text-sm font-medium">{error}</p>
                    </div>
                  </div>
                )}

                <div className="space-y-6">
                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-3">
                      Username
                    </label>
                    <input
                      type="text"
                      value={username}
                      onChange={(e) => setUsername(e.target.value)}
                      placeholder={`e.g., ${getCurrentRole()?.sampleUsername}`}
                      className="w-full px-4 py-4 border-2 border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all text-lg"
                      disabled={isLoading}
                    />
                  </div>

                  <div>
                    <label className="block text-sm font-semibold text-gray-700 mb-3">
                      Password
                    </label>
                    <div className="relative">
                      <input
                        type={showPassword ? 'text' : 'password'}
                        value={password}
                        onChange={(e) => setPassword(e.target.value)}
                        placeholder="Enter your password"
                        className="w-full px-4 py-4 pr-12 border-2 border-gray-200 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all text-lg"
                        disabled={isLoading}
                      />
                      <button
                        type="button"
                        onClick={() => setShowPassword(!showPassword)}
                        className="absolute right-4 top-1/2 transform -translate-y-1/2 text-gray-500 hover:text-gray-700 transition-colors"
                      >
                        {showPassword ? <FaEyeSlash size={20} /> : <FaEye size={20} />}
                      </button>
                    </div>
                  </div>

                  {/* Quick Fill Demo */}
                  <div className="p-4 bg-gradient-to-r from-gray-50 to-blue-50 rounded-xl border border-gray-200">
                    <p className="text-sm text-gray-600 mb-2">Quick fill for demo:</p>
                    <button
                      onClick={fillSampleCredentials}
                      className="text-sm text-blue-600 hover:text-blue-800 font-medium underline"
                      disabled={isLoading}
                    >
                      Fill sample credentials ({getCurrentRole()?.sampleUsername})
                    </button>
                  </div>

                  <div className="flex gap-4 pt-4">
                    <button
                      onClick={handleBack}
                      className="flex-1 py-4 px-6 border-2 border-gray-200 rounded-xl text-gray-700 font-semibold hover:bg-gray-50 hover:border-gray-300 transition-all"
                      disabled={isLoading}
                    >
                      Back
                    </button>
                    <button
                      onClick={handleLogin}
                      disabled={isLoading || !username || !password}
                      className="flex-1 py-4 px-6 bg-gradient-to-r from-blue-500 to-blue-600 text-white rounded-xl font-semibold hover:from-blue-600 hover:to-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-all transform hover:scale-105 flex items-center justify-center gap-2 shadow-lg"
                    >
                      {isLoading ? (
                        <>
                          <FaSpinner className="animate-spin" />
                          Logging in...
                        </>
                      ) : (
                        'Login'
                      )}
                    </button>
                  </div>
                </div>
              </div>
            )}
          </div>

          {/* Footer */}
          <div className="text-center mt-8">
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-white/60 backdrop-blur-sm rounded-full">
              <FaHeartbeat className="text-red-500 animate-pulse" />
              <span className="text-sm text-gray-600 font-medium">Healthcare Access • Nabha, Punjab</span>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
